parameters.jsCode:
return $input.all().map(item => {
  const isTrigger = item.json.issue ? true : false;

  const issueKey = isTrigger ? item.json.issue.key : item.json.key;
  const fields = isTrigger ? (item.json.issue.fields || {}) : (item.fields || {});

  const formatTime = (timeStr) => {
    if (!timeStr || timeStr === 'N/A') return 'N/A';
    return timeStr.replace('T', ' ').split('.')[0];
  };

  const statusName = fields.status ? fields.status.name : 'N/A';

  // --- THE LIMITER: Group matches into a rolling 3-second window ---
  const throttleWindow = Math.floor(Date.now() / 3000); 

  // --- NEW: Lifecycle Detector ---
  // Converts Jira's raw created and updated ISO strings to unix timestamps (milliseconds)
  const createdMs = fields.created ? new Date(fields.created).getTime() : 0;
  const updatedMs = fields.updated ? new Date(fields.updated).getTime() : 0;

  // If the creation time and update time match within 2 seconds, it's a "Created" event.
  // Otherwise, if updatedMs is significantly larger, it's an "Updated" event.
  const isCreated = Math.abs(updatedMs - createdMs) < 2000;

  return {
    json: {
      ticket_id: issueKey || 'N/A',
      summary: fields.summary || 'No Summary',
      assignee: fields.assignee ? fields.assignee.displayName : '👥 Unassigned',
      status: statusName,
      time_created: formatTime(fields.created),
      time_updated: formatTime(fields.updated),
      throttle_id: `${issueKey}-${statusName}-${throttleWindow}`,

      // --- NEW STATE OUTPUTS ---
      webhook_action: isCreated ? "CREATED" : "UPDATED"
    }
  };
});

